export enum UserRole {
  FARMER = 'Farmer',
  BUYER = 'Buyer',
  EXTENSION_WORKER = 'Extension Worker',
  ADMIN = 'Admin'
}

export interface FarmerProfile {
  id: string;
  name: string;
  region: string;
  crops_grown: string[];
  verification_status: boolean;
  trust_score: number;
}

export interface Diagnosis {
  id: string;
  crop_type: string;
  photo_url: string;
  disease_detected: string;
  pest_detected: string;
  severity_level: 'Low' | 'Medium' | 'High';
  treatment_recommendation: string;
  timestamp: string;
}

export interface MarketPrice {
  id: string;
  market_name: string;
  crop_type: string;
  price: number;
  broker_margin: number;
  timestamp: string;
}

export interface Question {
  id: string;
  farmer_id: string;
  question_text: string;
  timestamp: string;
  answers: Answer[];
}

export interface Answer {
  id: string;
  responder_id: string;
  answer_text: string;
  verified: boolean;
  timestamp: string;
}

export interface Alert {
  id: string;
  region: string;
  alert_type: string;
  severity: 'Info' | 'Warning' | 'Critical';
  message: string;
  timestamp: string;
}

import { GoogleGenAI, Type, GenerateContentResponse, Modality } from "@google/genai";

// Initialize the API client
const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

/**
 * AI Crop & Pest Diagnosis using Gemini 3 Pro (Image Analysis)
 */
export async function diagnoseCrop(imageBuffer: string, cropType: string): Promise<string> {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: {
      parts: [
        { inlineData: { data: imageBuffer.split(',')[1], mimeType: 'image/jpeg' } },
        { text: `Analyze this ${cropType} crop for pests and diseases. Provide a structured response with: Disease Name, Pest Name, Severity Level (Low/Medium/High), and Treatment Recommendation. Focus on Ethiopian agricultural contexts.` }
      ]
    },
    config: {
      thinkingConfig: { thinkingBudget: 32768 }
    }
  });
  return response.text || "No diagnosis could be generated.";
}

/**
 * Market Insights with Grounding (Gemini 3 Flash)
 */
export async function getMarketInsights(crop: string, region: string): Promise<{ text: string; sources: any[] }> {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `What are the current market prices and demand trends for ${crop} in the ${region} region of Ethiopia? Provide recent insights.`,
    config: {
      tools: [{ googleSearch: {} }]
    }
  });

  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  return {
    text: response.text || "Information not available.",
    sources
  };
}

/**
 * Nearby Facilities (Gemini 2.5 Flash with Maps)
 */
export async function getNearbyAgriculturalServices(lat: number, lng: number): Promise<{ text: string; sources: any[] }> {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash",
    contents: "Find agricultural service centers, cooperatives, and seed banks nearby.",
    config: {
      tools: [{ googleMaps: {} }],
      toolConfig: {
        retrievalConfig: {
          latLng: { latitude: lat, longitude: lng }
        }
      }
    }
  });
  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  return {
    text: response.text || "No facilities found.",
    sources
  };
}

/**
 * Low-latency Q&A (Gemini 2.5 Flash Lite)
 */
export async function askQuickQuestion(question: string): Promise<string> {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-lite-latest',
    contents: `Short, concise answer for an Ethiopian farmer: ${question}`
  });
  return response.text || "I'm not sure, please consult an extension worker.";
}

/**
 * Generate a visual mockup of crop health (Gemini 3 Pro Image)
 */
export async function generateFieldMockup(prompt: string): Promise<string | undefined> {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: {
      parts: [{ text: `A high-resolution satellite-style NDVI heatmap of an Ethiopian farm plot showing ${prompt}. 16:9 aspect ratio.` }]
    },
    config: {
      imageConfig: {
        aspectRatio: "16:9",
        imageSize: "1K"
      }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return undefined;
}

/**
 * Audio Transcription for Voice Input (Gemini 3 Flash)
 */
export async function transcribeAudio(base64Audio: string): Promise<string> {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Audio, mimeType: 'audio/wav' } },
        { text: "Transcribe this audio. If it's in Amharic or Oromo, translate it to English." }
      ]
    }
  });
  return response.text || "";
}

import React, { useState, useEffect } from 'react';
import { UserRole } from './types';
import Navigation from './components/Navigation';
import FarmerDashboard from './components/FarmerDashboard';
import BuyerDashboard from './components/BuyerDashboard';
import ExtensionDashboard from './components/ExtensionDashboard';
import AdminDashboard from './components/AdminDashboard';
import VoiceAssistant from './components/VoiceAssistant';
import { Sprout, UserCircle, Settings } from 'lucide-react';

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole>(UserRole.FARMER);
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  return (
    <div className="min-h-screen flex flex-col bg-gray-50 text-gray-900">
      {/* Header */}
      <header className="sticky top-0 z-40 bg-white border-b border-gray-100 px-4 py-3 flex items-center justify-between shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-[#FF6F61] p-2 rounded-lg">
            <Sprout className="text-white w-6 h-6" />
          </div>
          <h1 className="text-xl font-bold text-[#FF6F61]">Shega Farm</h1>
        </div>

        <div className="flex items-center gap-3">
          <select 
            value={role} 
            onChange={(e) => setRole(e.target.value as UserRole)}
            className="text-xs bg-gray-100 border-none rounded-full px-3 py-1.5 font-medium focus:ring-2 focus:ring-[#FF6F61]"
          >
            {Object.values(UserRole).map(r => (
              <option key={r} value={r}>{r}</option>
            ))}
          </select>
          <button className="p-2 rounded-full hover:bg-gray-100">
            <UserCircle className="w-6 h-6 text-gray-500" />
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 pb-24">
        {role === UserRole.FARMER && <FarmerDashboard />}
        {role === UserRole.BUYER && <BuyerDashboard />}
        {role === UserRole.EXTENSION_WORKER && <ExtensionDashboard />}
        {role === UserRole.ADMIN && <AdminDashboard />}
      </main>

      {/* Persistent Voice Assistant Trigger */}
      <VoiceAssistant />

      {/* Bottom Mobile Nav */}
      <Navigation role={role} />
    </div>
  );
};

export default App;

import React from 'react';
import { UserRole } from '../types';
import { Home, Search, ShoppingBag, MessageSquare, ShieldCheck, Activity } from 'lucide-react';

interface NavigationProps {
  role: UserRole;
}

const Navigation: React.FC<NavigationProps> = ({ role }) => {
  const farmerTabs = [
    { icon: Home, label: 'Home' },
    { icon: Search, label: 'Diagnosis' },
    { icon: ShoppingBag, label: 'Market' },
    { icon: MessageSquare, label: 'Forum' },
  ];

  const adminTabs = [
    { icon: Activity, label: 'Analytics' },
    { icon: ShieldCheck, label: 'Verify' },
    { icon: ShoppingBag, label: 'Oversight' },
    { icon: MessageSquare, label: 'Broadcast' },
  ];

  const tabs = role === UserRole.ADMIN ? adminTabs : farmerTabs;

  return (
    <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-100 px-6 py-2 flex justify-between items-center shadow-lg z-50">
      {tabs.map((tab, idx) => (
        <button key={idx} className="flex flex-col items-center gap-1 group">
          <div className={`p-1.5 rounded-xl transition-colors ${idx === 0 ? 'bg-orange-50 text-[#FF6F61]' : 'text-gray-400 group-hover:text-[#FF6F61]'}`}>
            <tab.icon className="w-6 h-6" />
          </div>
          <span className={`text-[10px] font-medium ${idx === 0 ? 'text-[#FF6F61]' : 'text-gray-500 group-hover:text-[#FF6F61]'}`}>
            {tab.label}
          </span>
        </button>
      ))}
    </nav>
  );
};

export default Navigation;

import React, { useState, useEffect } from 'react';
import { Camera, CloudRain, TrendingUp, AlertTriangle, ShieldCheck, CreditCard } from 'lucide-react';
import { diagnoseCrop, getMarketInsights } from '../services/geminiService';
import { Diagnosis } from '../types';

const FarmerDashboard: React.FC = () => {
  const [isDiagnosing, setIsDiagnosing] = useState(false);
  const [diagnosisResult, setDiagnosisResult] = useState<string | null>(null);
  const [marketInsights, setMarketInsights] = useState<{ text: string; sources: any[] } | null>(null);
  const [loadingMarket, setLoadingMarket] = useState(false);

  const handlePhotoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsDiagnosing(true);
    setDiagnosisResult(null);

    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = reader.result as string;
      try {
        const result = await diagnoseCrop(base64, 'Teff');
        setDiagnosisResult(result);
      } catch (err) {
        console.error(err);
        setDiagnosisResult("Error analyzing image. Please try again.");
      } finally {
        setIsDiagnosing(false);
      }
    };
    reader.readAsDataURL(file);
  };

  const fetchMarket = async () => {
    setLoadingMarket(true);
    try {
      const data = await getMarketInsights('Coffee', 'Oromia');
      setMarketInsights(data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoadingMarket(false);
    }
  };

  useEffect(() => {
    fetchMarket();
  }, []);

  return (
    <div className="p-4 space-y-6">
      {/* Welcome Card */}
      <div className="bg-gradient-to-br from-[#FF6F61] to-[#FFB6C1] rounded-2xl p-6 text-white shadow-xl shadow-[#FF6F61]/20">
        <h2 className="text-2xl font-bold mb-1">Hello, Abebe!</h2>
        <p className="text-white/80 text-sm">Your Teff crop is looking 15% better than last week.</p>
        <div className="mt-4 flex gap-4">
          <div className="bg-white/20 rounded-lg p-3 backdrop-blur-md flex-1">
            <p className="text-xs uppercase opacity-70 mb-1">Trust Score</p>
            <p className="text-xl font-bold">840</p>
          </div>
          <div className="bg-white/20 rounded-lg p-3 backdrop-blur-md flex-1">
            <p className="text-xs uppercase opacity-70 mb-1">Loan Eligibility</p>
            <p className="text-xl font-bold">12k ETB</p>
          </div>
        </div>
      </div>

      {/* AI Diagnosis Module */}
      <section>
        <div className="flex items-center justify-between mb-3">
          <h3 className="text-lg font-bold flex items-center gap-2">
            <Camera className="w-5 h-5 text-[#FF6F61]" />
            Crop Diagnosis
          </h3>
        </div>
        <div className="bg-white rounded-xl p-4 shadow-sm border border-gray-100 relative overflow-hidden">
          {isDiagnosing && (
            <div className="absolute inset-0 bg-white/80 backdrop-blur-sm z-10 flex flex-center items-center justify-center flex-col gap-2">
              <div className="w-8 h-8 border-4 border-[#FF6F61] border-t-transparent rounded-full animate-spin"></div>
              <p className="text-sm font-medium text-[#FF6F61]">AI Analyzing Crop Health...</p>
            </div>
          )}

          {diagnosisResult ? (
            <div className="space-y-3">
              <div className="p-3 bg-orange-50 rounded-lg border border-orange-100">
                <p className="text-sm leading-relaxed text-gray-700 whitespace-pre-line">{diagnosisResult}</p>
              </div>
              <button 
                onClick={() => setDiagnosisResult(null)}
                className="w-full py-2 bg-gray-100 rounded-lg text-sm font-semibold hover:bg-gray-200"
              >
                New Scan
              </button>
            </div>
          ) : (
            <label className="flex flex-col items-center justify-center border-2 border-dashed border-gray-200 rounded-xl p-8 cursor-pointer hover:border-[#FF6F61] transition-colors group">
              <Camera className="w-10 h-10 text-gray-300 group-hover:text-[#FF6F61] mb-2" />
              <p className="text-sm font-medium text-gray-500">Tap to upload crop photo</p>
              <p className="text-xs text-gray-400 mt-1">Get instant pest/disease advice</p>
              <input type="file" accept="image/*" className="hidden" onChange={handlePhotoUpload} />
            </label>
          )}
        </div>
      </section>

