import React from 'react';
import { UserRole } from '../types';
import { 
  Home, Search, ShoppingBag, MessageSquare, 
  ShieldCheck, Activity, Send, ShoppingCart, 
  Truck, ClipboardList, UserCheck, HelpCircle 
} from 'lucide-react';

interface NavigationProps {
  role: UserRole;
  activeTab: number;
  onTabChange: (index: number) => void;
}

const Navigation: React.FC<NavigationProps> = ({ role, activeTab, onTabChange }) => {
  const getTabs = () => {
    switch (role) {
      case UserRole.FARMER:
        return [
          { icon: Home, label: 'Home' },
          { icon: Search, label: 'Diagnosis' },
          { icon: ShoppingBag, label: 'Market' },
          { icon: MessageSquare, label: 'Forum' },
        ];
      case UserRole.BUYER:
        return [
          { icon: ShoppingCart, label: 'Market' },
          { icon: ClipboardList, label: 'Bids' },
          { icon: Truck, label: 'Logistics' },
        ];
      case UserRole.EXTENSION_WORKER:
        return [
          { icon: HelpCircle, label: 'Questions' },
          { icon: UserCheck, label: 'Verify' },
          { icon: MessageSquare, label: 'Advice' },
        ];
      case UserRole.ADMIN:
        return [
          { icon: Activity, label: 'Analytics' },
          { icon: ShieldCheck, label: 'Verify' },
          { icon: ShoppingBag, label: 'Oversight' },
          { icon: Send, label: 'Broadcast' },
        ];
      default:
        return [];
    }
  };

  const tabs = getTabs();

  return (
    <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-100 px-4 py-2 flex justify-around items-center shadow-[0_-4px_10px_rgba(0,0,0,0.05)] z-50">
      {tabs.map((tab, idx) => {
        const isActive = activeTab === idx;
        return (
          <button 
            key={idx} 
            onClick={() => onTabChange(idx)}
            className="flex flex-col items-center gap-1 min-w-[64px] transition-all duration-200"
          >
            <div className={`p-1.5 rounded-xl transition-all ${isActive ? 'bg-orange-100 text-[#FF6F61] scale-110' : 'text-gray-400'}`}>
              <tab.icon className="w-6 h-6" />
            </div>
            <span className={`text-[10px] font-bold tracking-tight ${isActive ? 'text-[#FF6F61]' : 'text-gray-500'}`}>
              {tab.label}
            </span>
          </button>
        );
      })}
    </nav>
  );
};

export default Navigation;

import React, { useState, useEffect } from 'react';
import { UserRole } from './types';
import Navigation from './components/Navigation';
import FarmerDashboard from './components/FarmerDashboard';
import BuyerDashboard from './components/BuyerDashboard';
import ExtensionDashboard from './components/ExtensionDashboard';
import AdminDashboard from './components/AdminDashboard';
import VoiceAssistant from './components/VoiceAssistant';
import { Sprout, UserCircle, Wifi, WifiOff, CloudUpload } from 'lucide-react';
import { SyncService } from './services/syncService';

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole>(UserRole.FARMER);
  const [activeTab, setActiveTab] = useState(0);
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [isSyncing, setIsSyncing] = useState(false);
  const [pendingCount, setPendingCount] = useState(SyncService.getQueue().length);

  // Reset tab when role changes
  useEffect(() => {
    setActiveTab(0);
  }, [role]);

  useEffect(() => {
    const handleOnline = () => {
      setIsOnline(true);
      performSync();
    };
    const handleOffline = () => setIsOnline(false);

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    if (navigator.onLine) performSync();

    const interval = setInterval(() => {
      setPendingCount(SyncService.getQueue().length);
    }, 2000);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
      clearInterval(interval);
    };
  }, []);

  const performSync = async () => {
    if (SyncService.hasPending()) {
      setIsSyncing(true);
      await SyncService.processQueue((id, success) => {
        console.log(`Synced ${id}: ${success}`);
      });
      setPendingCount(0);
      setIsSyncing(false);
    }
  };

  const renderContent = () => {
    switch (role) {
      case UserRole.FARMER:
        return <FarmerDashboard activeTab={activeTab} />;
      case UserRole.BUYER:
        return <BuyerDashboard activeTab={activeTab} />;
      case UserRole.EXTENSION_WORKER:
        return <ExtensionDashboard activeTab={activeTab} />;
      case UserRole.ADMIN:
        return <AdminDashboard activeTab={activeTab} />;
      default:
        return <div className="p-8 text-center text-gray-400">Select a Role</div>;
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-gray-50 text-gray-900">
      {/* Sync Banner */}
      {isSyncing && (
        <div className="bg-[#FF6F61] text-white text-[10px] font-bold py-1 px-4 flex items-center justify-center gap-2 animate-pulse sticky top-0 z-50">
          <CloudUpload className="w-3 h-3" /> Syncing your offline data...
        </div>
      )}

      {/* Header */}
      <header className="sticky top-0 z-40 bg-white border-b border-gray-100 px-4 py-3 flex items-center justify-between shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-[#FF6F61] p-2 rounded-lg">
            <Sprout className="text-white w-5 h-5" />
          </div>
          <div>
            <h1 className="text-lg font-bold text-[#FF6F61] leading-none">Shega Farm</h1>
            <div className="flex items-center gap-1 mt-0.5">
              {isOnline ? (
                <span className="flex items-center gap-1 text-[9px] text-green-500 font-bold uppercase tracking-wider">
                  <Wifi className="w-2.5 h-2.5" /> Online
                </span>
              ) : (
                <span className="flex items-center gap-1 text-[9px] text-red-500 font-bold uppercase tracking-wider">
                  <WifiOff className="w-2.5 h-2.5" /> Offline
                </span>
              )}
            </div>
          </div>
        </div>

        <div className="flex items-center gap-2">
          {pendingCount > 0 && !isSyncing && (
            <div className="bg-orange-100 text-orange-600 text-[9px] font-bold px-2 py-0.5 rounded-full">
              {pendingCount} Pending
            </div>
          )}
          <select 
            value={role} 
            onChange={(e) => setRole(e.target.value as UserRole)}
            className="text-[10px] bg-gray-100 border-none rounded-full px-3 py-1.5 font-bold focus:ring-1 focus:ring-[#FF6F61] outline-none cursor-pointer"
          >
            {Object.values(UserRole).map(r => (
              <option key={r} value={r}>{r}</option>
            ))}
          </select>
          <button className="p-1.5 rounded-full hover:bg-gray-100 text-gray-400">
            <UserCircle className="w-6 h-6" />
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 pb-24 max-w-2xl mx-auto w-full">
        {renderContent()}
      </main>

      <VoiceAssistant />
      <Navigation role={role} activeTab={activeTab} onTabChange={setActiveTab} />
    </div>
  );
};

export default App;

