  const [loadingMarket, setLoadingMarket] = useState(false);
  const [offlineQueued, setOfflineQueued] = useState(false);

  // Tab mapping: 0: Home, 1: Diagnosis, 2: Market, 3: Forum

  const handlePhotoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setOfflineQueued(false);
    setDiagnosisResult(null);

    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = reader.result as string;
      if (!navigator.onLine) {
        SyncService.enqueue({ type: 'DIAGNOSIS', payload: { image: base64, cropType: 'Teff' } });
        setOfflineQueued(true);
        return;
      }
      setIsDiagnosing(true);
      try {
        const result = await diagnoseCrop(base64, 'Teff');
        setDiagnosisResult(result);
      } catch (err) {
        SyncService.enqueue({ type: 'DIAGNOSIS', payload: { image: base64, cropType: 'Teff' } });
        setDiagnosisResult("Saved for offline processing.");
      } finally {
        setIsDiagnosing(false);
      }
    };
    reader.readAsDataURL(file);
  };

  const fetchMarket = async () => {
    if (!navigator.onLine) return;
    setLoadingMarket(true);
    try {
      const data = await getMarketInsights('Coffee', 'Oromia');
      setMarketInsights(data);
    } catch (err) {
